package com.school.sis.grade.entity;
import com.school.sis.common.audit.AuditableEntity; import jakarta.persistence.*; import java.math.BigDecimal; import java.time.LocalDate; import java.util.UUID;
@Entity @Table(name="grade_assessment_items") public class GradeAssessmentItem extends AuditableEntity {
 @Id private UUID id; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="gradebook_id") private ClassGradebook gradebook; @ManyToOne(fetch=FetchType.LAZY,optional=false) @JoinColumn(name="category_id") private ClassGradebookCategory category; @Column(nullable=false) private String title; @Column(name="maximum_score",nullable=false) private BigDecimal maximumScore; @Column(name="due_date") private LocalDate dueDate; @Column(name="sort_order",nullable=false) private int sortOrder; @Column(nullable=false) private boolean archived;
 @PrePersist void pre(){if(id==null)id=UUID.randomUUID();} public UUID getId(){return id;} public ClassGradebook getGradebook(){return gradebook;} public void setGradebook(ClassGradebook v){gradebook=v;} public ClassGradebookCategory getCategory(){return category;} public void setCategory(ClassGradebookCategory v){category=v;} public String getTitle(){return title;} public void setTitle(String v){title=v;} public BigDecimal getMaximumScore(){return maximumScore;} public void setMaximumScore(BigDecimal v){maximumScore=v;} public LocalDate getDueDate(){return dueDate;} public void setDueDate(LocalDate v){dueDate=v;} public int getSortOrder(){return sortOrder;} public void setSortOrder(int v){sortOrder=v;} public boolean isArchived(){return archived;} public void setArchived(boolean v){archived=v;}
}
